import java.io.*;
public class SharedRef {
    public static void main(String[] args) throws Exception {
        Object shared = new Object();
        ByteArrayOutputStream baos1 = new ByteArrayOutputStream();
        ByteArrayOutputStream baos2 = new ByteArrayOutputStream();
        // bug: two separate streams lose the shared identity
        new ObjectOutputStream(baos1).writeObject(shared);
        new ObjectOutputStream(baos2).writeObject(shared);
        // deserializing each gives independent objects
    }
